## JavaScript Debounce 函数

防抖（debounce）的核心思想：**在连续高频触发时，只在最后一次触发后的等待期内没有新触发，才真正执行回调**。

下面给出一个**完整、带类型注释、支持立即执行和取消**的实现：

```javascript
/**
 * 创建一个 debounce 函数
 * @param {Function} fn         - 要执行的原始函数
 * @param {number}   wait       - 等待时间（毫秒）
 * @param {boolean}  [immediate]- true 则在第一次触发时立即执行，之后 wait 内不再触发
 * @returns {Function} debounced 函数，带 .cancel() 方法
 */
function debounce(fn, wait, immediate = false) {
  let timer = null;
  let lastCallTime = 0;

  const debounced = function (...args) {
    const context = this;
    const now = Date.now();

    // —— immediate 模式：第一次立即执行 ——
    if (immediate && !timer) {
      fn.apply(context, args);
      // 记录这次调用时间，之后在 wait 内再次调用不会立即执行
      lastCallTime = now;
    }

    // 清除上一次的定时器
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // 设定新的定时器
    timer = setTimeout(() => {
      timer = null;
      // immediate 模式下：如果距离上次调用超过 wait，再执行一次让"尾随"生效
      // 非 immediate 模式：正常执行
      if (!immediate || now - lastCallTime >= wait) {
        fn.apply(context, args);
      }
    }, wait);
  };

  /**
   * 取消尚未执行的调用
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
  };

  /**
   * 立即调用并取消所有等待
   */
  debounced.flush = function (...args) {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    fn.apply(this, args);
  };

  return debounced;
}
```

---

### 用法示例

```javascript
// 1. 搜索框防抖 —— 用户停止输入 300ms 后才请求
const search = debounce((query) => {
  console.log('搜索:', query);
}, 300);

searchInput.addEventListener('input', (e) => {
  search(e.target.value);
});

// 2. 窗口 resize —— 等用户调整完再执行
const onResize = debounce(() => {
  console.log('窗口大小:', window.innerWidth);
}, 200);
window.addEventListener('resize', onResize);

// 3. immediate 模式 —— 提交按钮防连点，第一次立即执行
const submit = debounce(() => {
  console.log('提交中...');
}, 1000, true);
```

---

### 两种模式对比

| 模式 | `immediate = false`（默认） | `immediate = true` |
|------|---------------------------|-------------------|
| **执行时机** | 停止触发 wait 毫秒后 | 第一次触发立即执行，之后 wait 内不再触发 |
| **适用场景** | 输入框搜索、resize | 按钮防连点、"保存"操作 |
| **行为俗称** | 尾随执行（leading 前不执行） | 首尾都执行（leading + trailing） |

---

### 进阶：Lodash 风格（`leading` / `trailing` / `maxWait`）

如果面试中想展示更深的功底，可以提 Lodash 的增强版：

```javascript
function debounce(fn, wait, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;
  let timer = null, lastArgs = null, lastThis = null;
  let lastCallTime = 0, lastInvokeTime = 0;

  function invokeFunc(time) {
    lastInvokeTime = time;
    fn.apply(lastThis, lastArgs);
    lastArgs = lastThis = null;
  }

  function startTimer(pendingFunc, wait) {
    timer = setTimeout(pendingFunc, wait);
  }

  function trailingEdge(time) {
    timer = null;
    if (trailing && lastArgs) invokeFunc(time);
    lastArgs = lastThis = null;
  }

  function debounced(...args) {
    const time = Date.now();
    const isInvoking = time - lastInvokeTime >= (maxWait || wait);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking && leading) {
      invokeFunc(time);
    }
    if (!timer) {
      startTimer(() => trailingEdge(Date.now()), wait);
    }
  }

  debounced.cancel = function () {
    clearTimeout(timer);
    timer = null; lastArgs = lastThis = null;
  };

  return debounced;
}
```

核心要点面试时常问：
- **this 指向** — 用 `apply(context, args)` 保留调用时的 `this`
- **闭包保存 timer** — 每次调用清除/新建定时器
- **immediate / leading** 区别
- **cancel 方法** — 清理定时器避免内存泄漏

